const topic = $('주제 입력 폼').first().json['주제'];
const tone  = $('주제 입력 폼').first().json['톤'] || '친근한';
const text  = (n) => $(n).first().json.candidates?.[0]?.content?.parts?.[0]?.text || '';
const cut   = (s) => String(s).slice(0, 1900);
const imgPrompt = `clean modern vibrant social media hero image about ${topic}, no text, no words, no letters, no typography, no captions, professional, high quality`;
const imageUrl = `https://image.pollinations.ai/prompt/${encodeURIComponent(imgPrompt)}?width=1024&height=1024&nologo=true&seed=42`;
return [
  { json: { platform: 'Instagram', topic, tone, body: cut(text('Gemini 인스타그램')), imageUrl } },
  { json: { platform: 'Blog',      topic, tone, body: cut(text('Gemini 블로그')),     imageUrl } },
  { json: { platform: 'X',         topic, tone, body: cut(text('Gemini X')),          imageUrl } },
];
